#include <bits/stdc++.h>
using namespace std;
const unsigned long long b=131,maxn=2e3+5;
unsigned long long n,h[6][maxn],p[maxn];
vector<string> s(10);
void init_hash() {
	p[0]=1;
	for(unsigned long long i=1; i<=n; i++) {
		for(unsigned long long j=1; j<s[i].size(); j++) {
			h[i][j]=h[i][j-1]*b+s[i][j];
		}
	}
	for(unsigned long long i=1; i<=maxn; i++) {
		p[i]=p[i-1]*b;
	}
}
unsigned long long get_hash(unsigned long long id,unsigned long long l,unsigned long long r) {
	return h[id][r]-h[id][l-1]*p[r-l+1];
}
bool check(unsigned long long x) {
	unordered_map<unsigned long long,int> cnt;
	for(unsigned long long i=1; i<=n; i++) {
		unordered_map<unsigned long long,int> vis;
		for(unsigned long long j=x; j<s[i].length(); j++) {
			unsigned long long v=get_hash(i,j-x+1,j);
			if(!vis[v]) {
				vis[v]=1;
				cnt[v]++;
				if(cnt[v]==n) {
					return 1;
				}
			}
		}
	}
	return 0;
}
unsigned long long maxx=maxn;
unsigned long long find_pos() {
	unsigned long long l=1,r=maxx,ans=0;
	while(l<=r) {
		unsigned long long mid=l+r>>1;
		if(check(mid)) {
			ans=mid;
			l=mid+1;
		} else {
			r=mid-1;
		}
	}
	return ans;
}
signed main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n;
	for(unsigned long long i=1; i<=n; i++) {
		cin>>s[i];
		maxx=min(int(maxx),(int)s[i].size());
		s[i]=' '+s[i];
	}
	init_hash();
	cout<<find_pos();
	return 0;
}
